default.curl:
curl --location 'https://[workspace-id].cn-beijing.maas.aliyuncs.com/api/v1/services/aigc/image2video/video-synthesis/' \
--header 'X-DashScope-Async: enable' \
--header "Authorization: Bearer $DASHSCOPE_API_KEY" \
--header 'Content-Type: application/json' \
--data '{
    "model": "animate-anyone-gen2",
    "input": {
        "image_url": "https://help-static-aliyun-doc.aliyuncs.com/file-manage-files/zh-CN/20250912/ythwqz/aa-%E5%9B%BE%E5%83%8F%E6%A3%80%E6%B5%8B.png",
        "template_id": "AACT.xxx.xxx-xxx.xxx" 
    },
      "parameters": {
         "use_ref_img_bg": false,
         "video_ratio": "9:16"
    }
  }'

curl -X GET https://[workspace-id].cn-beijing.maas.aliyuncs.com/api/v1/tasks/<YOUR_TASK_ID> \
--header "Authorization: Bearer $DASHSCOPE_API_KEY"
